import { NextRequest, NextResponse } from "next/server";
import crypto from "crypto";

// POST /api/checkout/create-order
export async function POST(req: NextRequest) {
  const { amount } = await req.json();

  const body = JSON.stringify({
    amount: Math.round(amount * 100), // paise
    currency: "INR",
  });

  const auth = Buffer.from(
    `${process.env.RAZORPAY_KEY_ID}:${process.env.RAZORPAY_KEY_SECRET}`
  ).toString("base64");

  const res = await fetch("https://api.razorpay.com/v1/orders", {
    method: "POST",
    headers: {
      Authorization: `Basic ${auth}`,
      "Content-Type": "application/json",
    },
    body,
  });

  const data = await res.json();
  return NextResponse.json(data);
}

import { NextRequest, NextResponse } from "next/server";
import crypto from "crypto";
import { prisma } from "@/lib/prisma";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";

export async function POST(req: NextRequest) {
  const body = await req.json();
  const { razorpay_order_id, razorpay_payment_id, razorpay_signature, orderData } = body;

  // Verify signature
  const sign = crypto
    .createHmac("sha256", process.env.RAZORPAY_KEY_SECRET || "")
    .update(`${razorpay_order_id}|${razorpay_payment_id}`)
    .digest("hex");

  if (sign !== razorpay_signature) {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  const session = await getServerSession(authOptions);
  const userId = session?.user?.id;

  if (userId) {
    const total = orderData.items.reduce((s: number, i: any) => s + i.price * i.quantity, 0);
    await prisma.order.create({
      data: {
        userId,
        totalAmount: total,
        paymentId: razorpay_payment_id,
        status: "PAID",
        address: JSON.stringify(orderData.address),
        items: {
          create: orderData.items.map((item: any) => ({
            productId: item.id,
            quantity: item.quantity,
            size: item.size,
            color: item.color,
            price: item.price,
          })),
        },
      },
    });
  }

  return NextResponse.json({ success: true });
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Shield, Truck } from "lucide-react";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";
import { useCartStore } from "@/store/cart";
import Image from "next/image";

const RAZORPAY_KEY = process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || "";

declare global {
  interface Window {
    Razorpay: any;
  }
}

export default function CheckoutPage() {
  const { items, totalPrice, clearCart } = useCartStore();
  const [payMethod, setPayMethod] = useState<"razorpay" | "cod">("razorpay");
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ name: "", email: "", phone: "", address: "", city: "", pincode: "" });

  const total = totalPrice();
  const shipping = total >= 1499 ? 0 : 99;
  const grand = total + shipping;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));

  const handleRazorpay = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/checkout/create-order", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount: grand }),
      });
      const data = await res.json();

      const rzp = new window.Razorpay({
        key: RAZORPAY_KEY,
        amount: data.amount,
        currency: "INR",
        name: "AERON",
        description: "Order Payment",
        order_id: data.id,
        handler: async (response: any) => {
          await fetch("/api/checkout/verify", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ ...response, orderData: { items, address: form } }),
          });
          clearCart();
          window.location.href = "/order-confirmation";
        },
        prefill: { name: form.name, email: form.email, contact: form.phone },
        theme: { color: "#111111" },
      });
      rzp.open();
    } finally {
      setLoading(false);
    }
  };

  const handleCOD = async () => {
    setLoading(true);
    await fetch("/api/checkout/cod", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ items, address: form, total: grand }),
    });
    clearCart();
    window.location.href = "/order-confirmation";
    setLoading(false);
  };

  return (
    <>
      <Navbar />
      <main className="pt-20 min-h-screen bg-[#FAFAFA]">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-3xl font-black tracking-tight mb-10"
          >
            Checkout
          </motion.h1>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
            {/* Left: Form */}
            <div className="lg:col-span-7 space-y-8">
              {/* Contact */}
              <div className="bg-white rounded-2xl p-6 shadow-sm">
                <h2 className="font-bold text-lg mb-5">Contact Information</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {[
                    { label: "Full Name", name: "name", type: "text" },
                    { label: "Email", name: "email", type: "email" },
                    { label: "Phone", name: "phone", type: "tel" },
                  ].map((f) => (
                    <div key={f.name} className={f.name === "phone" ? "sm:col-span-2" : ""}>
                      <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase tracking-wider">{f.label}</label>
                      <input
                        type={f.type}
                        name={f.name}
                        value={form[f.name as keyof typeof form]}
                        onChange={handleChange}
                        className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm focus:outline-none focus:border-[#111] transition-colors"
                        required
                      />
                    </div>
                  ))}
                </div>
              </div>

              {/* Address */}
              <div className="bg-white rounded-2xl p-6 shadow-sm">
                <h2 className="font-bold text-lg mb-5">Delivery Address</h2>
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase tracking-wider">Street Address</label>
                    <input name="address" value={form.address} onChange={handleChange} className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm focus:outline-none focus:border-[#111]" required />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase tracking-wider">City</label>
                      <input name="city" value={form.city} onChange={handleChange} className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm focus:outline-none focus:border-[#111]" required />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase tracking-wider">Pincode</label>
                      <input name="pincode" value={form.pincode} onChange={handleChange} className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm focus:outline-none focus:border-[#111]" required />
                    </div>
                  </div>
                </div>
              </div>

              {/* Payment */}
              <div className="bg-white rounded-2xl p-6 shadow-sm">
                <h2 className="font-bold text-lg mb-5">Payment Method</h2>
                <div className="space-y-3">
                  {[
                    { value: "razorpay", label: "Online Payment (UPI, Cards, NetBanking)", sub: "Secured by Razorpay" },
                    { value: "cod", label: "Cash on Delivery", sub: "Pay when you receive your order" },
                  ].map((opt) => (
                    <label key={opt.value} className={`flex items-center gap-4 p-4 border-2 rounded-xl cursor-pointer transition-all ${payMethod === opt.value ? "border-[#111] bg-gray-50" : "border-gray-200"}`}>
                      <input
                        type="radio"
                        name="payment"
                        value={opt.value}
                        checked={payMethod === opt.value}
                        onChange={() => setPayMethod(opt.value as "razorpay" | "cod")}
                        className="accent-[#111]"
                      />
                      <div>
                        <p className="font-semibold text-sm">{opt.label}</p>
                        <p className="text-xs text-gray-500">{opt.sub}</p>
                      </div>
                    </label>
                  ))}
                </div>
              </div>
            </div>

            {/* Right: Order Summary */}
            <div className="lg:col-span-5">
              <div className="bg-white rounded-2xl p-6 shadow-sm sticky top-24">
                <h2 className="font-bold text-lg mb-5">Order Summary</h2>
                <div className="space-y-4 mb-6">
                  {items.map((item) => (
                    <div key={`${item.id}-${item.size}-${item.color}`} className="flex gap-3">
                      <div className="relative w-14 h-16 rounded-lg overflow-hidden bg-gray-100 flex-shrink-0">
                        <Image src={item.image} alt={item.name} fill className="object-cover" />
                        <span className="absolute -top-1 -right-1 bg-[#111] text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center">
                          {item.quantity}
                        </span>
                      </div>
                      <div className="flex-1">
                        <p className="font-medium text-sm line-clamp-1">{item.name}</p>
                        <p className="text-xs text-gray-500">{item.size} / {item.color}</p>
                        <p className="font-bold text-sm mt-1">₹{(item.price * item.quantity).toLocaleString()}</p>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="border-t border-gray-100 pt-4 space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-500">Subtotal</span>
                    <span>₹{total.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-500">Shipping</span>
                    <span className={shipping === 0 ? "text-green-600 font-semibold" : ""}>{shipping === 0 ? "Free" : `₹${shipping}`}</span>
                  </div>
                  <div className="flex justify-between font-black text-lg pt-2 border-t border-gray-100 mt-2">
                    <span>Total</span>
                    <span>₹{grand.toLocaleString()}</span>
                  </div>
                </div>

                <motion.button
                  onClick={payMethod === "razorpay" ? handleRazorpay : handleCOD}
                  whileTap={{ scale: 0.98 }}
                  disabled={loading || items.length === 0}
                  className="mt-6 w-full bg-[#111] text-white py-4 text-sm font-bold tracking-widest uppercase hover:bg-stone-800 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loading ? "Processing..." : payMethod === "razorpay" ? "Pay Now" : "Place Order (COD)"}
                </motion.button>

                <div className="flex items-center justify-center gap-2 mt-4 text-xs text-gray-400">
                  <Shield size={12} />
                  <span>Secure & encrypted checkout</span>
                </div>
                <div className="flex items-center justify-center gap-2 mt-1 text-xs text-gray-400">
                  <Truck size={12} />
                  <span>Free shipping above ₹1,499</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Razorpay Script */}
      <script src="https://checkout.razorpay.com/v1/checkout.js" async />
      <Footer />
    </>
  );
}

"use client";

import { useState } from "react";
import { Search as SearchIcon } from "lucide-react";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";

export default function SearchPage() {
  const [query, setQuery] = useState("");

  return (
    <>
      <Navbar />
      <main className="min-h-screen pt-32 pb-24 bg-white">
        <div className="max-w-3xl mx-auto px-4 sm:px-6 text-center">
          <h1 className="text-4xl font-black uppercase tracking-tighter mb-8">Search Store</h1>
          <div className="relative max-w-xl mx-auto mb-16">
            <input
              type="text"
              placeholder="Search products, categories..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="w-full text-lg border-b-2 border-gray-200 focus:border-[#111] px-4 py-4 pr-12 outline-none transition-colors bg-transparent"
              autoFocus
            />
            <SearchIcon className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400" size={24} />
          </div>

          <div className="text-gray-500">
            {query.length > 2 ? (
              <p>Searching for "{query}"... (Demo mode: no results found)</p>
            ) : (
              <p>Type at least 3 characters to search.</p>
            )}
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
}

"use client";

import Image from "next/image";
import Link from "next/link";
import { Heart } from "lucide-react";
import { motion } from "framer-motion";
import { useWishlistStore } from "@/store/wishlist";

interface ProductCardProps {
  id: string;
  name: string;
  price: number;
  originalPrice?: number;
  image: string;
  hoverImage?: string;
  category: string;
  isNew?: boolean;
}

export default function ProductCard({
  id, name, price, originalPrice, image, hoverImage, category, isNew,
}: ProductCardProps) {
  const { addItem, removeItem, hasItem } = useWishlistStore();
  const wishlisted = hasItem(id);

  const toggleWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    wishlisted ? removeItem(id) : addItem({ id, name, price, image });
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.5 }}
    >
      <Link href={`/shop/${id}`} className="group block">
        {/* Image */}
        <div className="relative overflow-hidden bg-[#F2F2EE] aspect-[3/4] rounded-xl">
          <Image
            src={image}
            alt={name}
            fill
            className={`object-cover transition-opacity duration-500 ${
              hoverImage ? "group-hover:opacity-0" : ""
            }`}
            sizes="(max-width: 768px) 50vw, 25vw"
          />
          {hoverImage && (
            <Image
              src={hoverImage}
              alt={name}
              fill
              className="object-cover opacity-0 group-hover:opacity-100 transition-opacity duration-500"
              sizes="(max-width: 768px) 50vw, 25vw"
            />
          )}

          {/* Badges */}
          <div className="absolute top-3 left-3 flex gap-2">
            {isNew && (
              <span className="bg-[#111] text-white text-[10px] font-semibold px-2 py-1 tracking-wider rounded-md">
                NEW
              </span>
            )}
            {originalPrice && originalPrice > price && (
              <span className="bg-red-500 text-white text-[10px] font-semibold px-2 py-1 tracking-wider rounded-md">
                {Math.round(((originalPrice - price) / originalPrice) * 100)}% OFF
              </span>
            )}
          </div>

          {/* Wishlist */}
          <button
            onClick={toggleWishlist}
            className="absolute top-3 right-3 p-2 bg-white/80 backdrop-blur-sm rounded-full opacity-0 group-hover:opacity-100 transition-all duration-200 hover:scale-110"
          >
            <Heart
              size={16}
              className={wishlisted ? "fill-red-500 stroke-red-500" : "stroke-gray-700"}
            />
          </button>

          {/* Quick Add */}
          <div className="absolute bottom-0 left-0 right-0 translate-y-full group-hover:translate-y-0 transition-transform duration-300">
            <button className="w-full bg-[#111] text-white py-3 text-xs font-semibold tracking-widest uppercase hover:bg-stone-800 transition-colors">
              Quick Add
            </button>
          </div>
        </div>

        {/* Info */}
        <div className="mt-3 space-y-1">
          <p className="text-[11px] text-gray-400 font-medium tracking-wider uppercase">{category}</p>
          <h3 className="text-sm font-semibold text-[#111] group-hover:text-gray-600 transition-colors line-clamp-2">
            {name}
          </h3>
          <div className="flex items-baseline gap-2">
            <span className="font-bold text-[#111]">₹{price.toLocaleString()}</span>
            {originalPrice && originalPrice > price && (
              <span className="text-sm text-gray-400 line-through">₹{originalPrice.toLocaleString()}</span>
            )}
          </div>
        </div>
      </Link>
    </motion.div>
  );
}

import type { NextAuthOptions } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import bcrypt from "bcrypt";

export const authOptions: NextAuthOptions = {
  // No adapter — JWT strategy is self-contained, no DB needed for sessions
  providers: [
    CredentialsProvider({
      name: "credentials",
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials?.password) return null;

        try {
          // Dynamic import so the app doesn't crash if DB is unreachable
          const { prisma } = await import("./prisma");
          const user = await prisma.user.findUnique({
            where: { email: credentials.email },
          });

          if (!user || !user.password) return null;

          const isValid = await bcrypt.compare(credentials.password, user.password);
          if (!isValid) return null;

          return { id: user.id, name: user.name, email: user.email, role: user.role };
        } catch {
          // DB not available — login fails gracefully
          return null;
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.id = user.id;
        token.role = (user as any).role ?? "USER";
      }
      return token;
    },
    async session({ session, token }) {
      if (token && session.user) {
        session.user.id = token.id as string;
        session.user.role = token.role as string;
      }
      return session;
    },
  },
  session: { strategy: "jwt" },
  secret: process.env.NEXTAUTH_SECRET,
  pages: { signIn: "/login" },
};

import NextAuth, { DefaultSession } from "next-auth";
import { DefaultJWT } from "next-auth/jwt";

declare module "next-auth" {
  interface Session {
    user: {
      id: string;
      role: string;
    } & DefaultSession["user"];
  }

  interface User {
    id: string;
    role: string;
  }
}

declare module "next-auth/jwt" {
  interface JWT extends DefaultJWT {
    id: string;
    role: string;
  }
}
